/**
 * CI Integration for Hardware Timing Validation
 * 
 * Enables automated timing validation in continuous integration pipelines
 * with performance regression detection.
 */

import { HardwareBenchmark, BenchmarkResult } from './hardware-benchmark';
import { VideoFrameValidator, VideoFrameValidationResult } from './video-frame-validation';

export interface CIValidationConfig {
  baselineFile?: string;
  thresholds: {
    timingPrecision: number; // max jitter in ms
    fpsMinimum: number;
    frameVariance: number; // max std deviation in ms
    memoryLimit: number; // max heap usage in MB
  };
  exitOnFailure: boolean;
  generateArtifacts: boolean;
  outputFormat: 'json' | 'junit' | 'markdown';
}

export interface CIValidationResult {
  passed: boolean;
  timestamp: number;
  environment: {
    ci: boolean;
    platform: string;
    node: string;
  };
  benchmarkResult: BenchmarkResult;
  videoFrameResult: VideoFrameValidationResult;
  regressions: RegressionReport[];
  artifacts: {
    report?: string;
    data?: string;
    charts?: string;
  };
}

export interface RegressionReport {
  metric: string;
  baseline: number;
  current: number;
  change: number; // percentage
  threshold: number;
  severity: 'warning' | 'error';
}

export interface BaselineData {
  version: string;
  timestamp: number;
  environment: string;
  metrics: {
    timingPrecision: number;
    avgFPS: number;
    frameVariance: number;
    memoryUsage: number;
  };
}

export class CIValidator {
  private config: CIValidationConfig;
  private baseline: BaselineData | null = null;

  constructor(config: Partial<CIValidationConfig> = {}) {
    this.config = {
      thresholds: {
        timingPrecision: 2,
        fpsMinimum: 58,
        frameVariance: 2,
        memoryLimit: 100
      },
      exitOnFailure: true,
      generateArtifacts: true,
      outputFormat: 'json',
      ...config
    };
  }

  /**
   * Run full CI validation suite
   */
  async runValidation(): Promise<CIValidationResult> {
    console.log('🚀 Starting CI timing validation...\n');

    // Load baseline if available
    if (this.config.baselineFile) {
      await this.loadBaseline(this.config.baselineFile);
    }

    // Run hardware benchmark
    const benchmark = new HardwareBenchmark();
    const benchmarkResult = await benchmark.runFullBenchmark();

    // Run video frame validation
    const videoValidator = new VideoFrameValidator();
    const videoFrameResult = await videoValidator.validate();

    // Detect regressions
    const regressions = this.detectRegressions(benchmarkResult);

    // Determine overall pass/fail
    const passed = this.evaluateResults(benchmarkResult, videoFrameResult, regressions);

    // Generate artifacts
    const artifacts: CIValidationResult['artifacts'] = {};
    if (this.config.generateArtifacts) {
      artifacts.report = this.generateReport(benchmarkResult, videoFrameResult, regressions);
      artifacts.data = JSON.stringify({ benchmarkResult, videoFrameResult }, null, 2);

      if (this.config.outputFormat === 'markdown') {
        artifacts.charts = this.generateCharts(benchmarkResult);
      }
    }

    const result: CIValidationResult = {
      passed,
      timestamp: Date.now(),
      environment: {
        ci: !!process.env.CI,
        platform: process.platform,
        node: process.version
      },
      benchmarkResult,
      videoFrameResult,
      regressions,
      artifacts
    };

    // Output results
    this.outputResults(result);

    // Exit with appropriate code if configured
    if (this.config.exitOnFailure && !passed) {
      process.exit(1);
    }

    return result;
  }

  /**
   * Load baseline metrics
   */
  private async loadBaseline(file: string): Promise<void> {
    try {
      const fs = await import('fs/promises');
      const data = await fs.readFile(file, 'utf-8');
      this.baseline = JSON.parse(data);
      console.log(`📊 Loaded baseline from ${file}`);
    } catch (error) {
      console.warn(`⚠️  Could not load baseline: ${error}`);
    }
  }

  /**
   * Detect performance regressions
   */
  private detectRegressions(result: BenchmarkResult): RegressionReport[] {
    const regressions: RegressionReport[] = [];

    if (!this.baseline) {
      return regressions;
    }

    // Check timing precision
    const currentTiming = result.performance.timing.stimulusOnsetJitter;
    const baselineTiming = this.baseline.metrics.timingPrecision;
    const timingChange = ((currentTiming - baselineTiming) / baselineTiming) * 100;

    if (timingChange > 10) {
      regressions.push({
        metric: 'Timing Precision',
        baseline: baselineTiming,
        current: currentTiming,
        change: timingChange,
        threshold: 10,
        severity: timingChange > 20 ? 'error' : 'warning'
      });
    }

    // Check FPS
    const currentFPS = result.performance.fps.average;
    const baselineFPS = this.baseline.metrics.avgFPS;
    const fpsChange = ((baselineFPS - currentFPS) / baselineFPS) * 100;

    if (fpsChange > 5) {
      regressions.push({
        metric: 'Frame Rate',
        baseline: baselineFPS,
        current: currentFPS,
        change: -fpsChange,
        threshold: 5,
        severity: fpsChange > 10 ? 'error' : 'warning'
      });
    }

    // Check frame variance
    const currentVariance = result.performance.frameVariance.standardDeviation;
    const baselineVariance = this.baseline.metrics.frameVariance;
    const varianceChange = ((currentVariance - baselineVariance) / baselineVariance) * 100;

    if (varianceChange > 15) {
      regressions.push({
        metric: 'Frame Variance',
        baseline: baselineVariance,
        current: currentVariance,
        change: varianceChange,
        threshold: 15,
        severity: varianceChange > 30 ? 'error' : 'warning'
      });
    }

    // Check memory usage
    const currentMemory = result.performance.memory.heapUsed;
    const baselineMemory = this.baseline.metrics.memoryUsage;
    const memoryChange = ((currentMemory - baselineMemory) / baselineMemory) * 100;

    if (memoryChange > 20) {
      regressions.push({
        metric: 'Memory Usage',
        baseline: baselineMemory,
        current: currentMemory,
        change: memoryChange,
        threshold: 20,
        severity: memoryChange > 50 ? 'error' : 'warning'
      });
    }

    return regressions;
  }

  /**
   * Evaluate overall pass/fail
   */
  private evaluateResults(
    benchmark: BenchmarkResult,
    videoFrame: VideoFrameValidationResult,
    regressions: RegressionReport[]
  ): boolean {
    // Check threshold violations
    const timingMet = benchmark.performance.timing.stimulusOnsetJitter <= this.config.thresholds.timingPrecision;
    const fpsMet = benchmark.performance.fps.percentiles.p95 >= this.config.thresholds.fpsMinimum;
    const varianceMet = benchmark.performance.frameVariance.standardDeviation <= this.config.thresholds.frameVariance;
    const memoryMet = benchmark.performance.memory.heapUsed <= this.config.thresholds.memoryLimit;

    // Check for critical regressions
    const hasCriticalRegression = regressions.some(r => r.severity === 'error');

    // Video frame callback should have high consistency if supported
    const videoFrameMet = !videoFrame.supported || videoFrame.consistency >= 90;

    return timingMet && fpsMet && varianceMet && memoryMet && !hasCriticalRegression && videoFrameMet;
  }

  /**
   * Generate comprehensive report
   */
  private generateReport(
    benchmark: BenchmarkResult,
    videoFrame: VideoFrameValidationResult,
    regressions: RegressionReport[]
  ): string {
    const passed = this.evaluateResults(benchmark, videoFrame, regressions);

    let report = `# CI Timing Validation Report

**Status**: ${passed ? '✅ PASSED' : '❌ FAILED'}
**Date**: ${new Date().toISOString()}
**Environment**: ${process.env.CI ? 'CI' : 'Local'} (${process.platform})

## Summary

### Timing Precision
- **Stimulus Onset Jitter**: ${benchmark.performance.timing.stimulusOnsetJitter.toFixed(2)}ms (threshold: ${this.config.thresholds.timingPrecision}ms)
- **Status**: ${benchmark.performance.timing.stimulusOnsetJitter <= this.config.thresholds.timingPrecision ? '✅' : '❌'}

### Frame Rate
- **95th Percentile FPS**: ${benchmark.performance.fps.percentiles.p95.toFixed(1)} (threshold: ${this.config.thresholds.fpsMinimum})
- **Status**: ${benchmark.performance.fps.percentiles.p95 >= this.config.thresholds.fpsMinimum ? '✅' : '❌'}

### Frame Variance
- **Standard Deviation**: ${benchmark.performance.frameVariance.standardDeviation.toFixed(2)}ms (threshold: ${this.config.thresholds.frameVariance}ms)
- **Status**: ${benchmark.performance.frameVariance.standardDeviation <= this.config.thresholds.frameVariance ? '✅' : '❌'}

### Memory Usage
- **Heap Used**: ${benchmark.performance.memory.heapUsed.toFixed(1)}MB (threshold: ${this.config.thresholds.memoryLimit}MB)
- **Status**: ${benchmark.performance.memory.heapUsed <= this.config.thresholds.memoryLimit ? '✅' : '❌'}

### Video Frame Callback
- **Supported**: ${videoFrame.supported ? '✅' : '❌'}
- **Consistency**: ${videoFrame.consistency?.toFixed(1) || 'N/A'}%
`;

    if (regressions.length > 0) {
      report += '\n## Performance Regressions\n\n';
      regressions.forEach(reg => {
        const icon = reg.severity === 'error' ? '🔴' : '🟡';
        report += `${icon} **${reg.metric}**: ${reg.current.toFixed(2)} (baseline: ${reg.baseline.toFixed(2)}, change: ${reg.change > 0 ? '+' : ''}${reg.change.toFixed(1)}%)\n`;
      });
    }

    if (benchmark.validation.warnings.length > 0) {
      report += '\n## Warnings\n\n';
      benchmark.validation.warnings.forEach(warning => {
        report += `- ${warning}\n`;
      });
    }

    if (benchmark.validation.recommendations.length > 0) {
      report += '\n## Recommendations\n\n';
      benchmark.validation.recommendations.forEach(rec => {
        report += `- ${rec}\n`;
      });
    }

    return report;
  }

  /**
   * Generate performance charts (ASCII for CI)
   */
  private generateCharts(benchmark: BenchmarkResult): string {
    const fps = benchmark.performance.fps;

    let charts = '## Performance Charts\n\n';

    // FPS distribution chart
    charts += '### FPS Distribution\n```\n';
    charts += `Min    [${this.generateBar(fps.min, 0, 144)}] ${fps.min.toFixed(1)}\n`;
    charts += `Avg    [${this.generateBar(fps.average, 0, 144)}] ${fps.average.toFixed(1)}\n`;
    charts += `P95    [${this.generateBar(fps.percentiles.p95, 0, 144)}] ${fps.percentiles.p95.toFixed(1)}\n`;
    charts += `Max    [${this.generateBar(fps.max, 0, 144)}] ${fps.max.toFixed(1)}\n`;
    charts += '```\n';

    return charts;
  }

  /**
   * Generate ASCII bar for charts
   */
  private generateBar(value: number, min: number, max: number): string {
    const width = 30;
    const normalized = (value - min) / (max - min);
    const filled = Math.round(normalized * width);
    return '█'.repeat(filled) + '░'.repeat(width - filled);
  }

  /**
   * Output results in specified format
   */
  private outputResults(result: CIValidationResult): void {
    switch (this.config.outputFormat) {
      case 'json':
        console.log(JSON.stringify(result, null, 2));
        break;

      case 'junit':
        console.log(this.generateJUnitReport(result));
        break;

      case 'markdown':
        console.log(result.artifacts.report);
        break;
    }
  }

  /**
   * Generate JUnit XML report for CI systems
   */
  private generateJUnitReport(result: CIValidationResult): string {
    const testCases = [
      {
        name: 'TimingPrecision',
        passed: result.benchmarkResult.performance.timing.stimulusOnsetJitter <= this.config.thresholds.timingPrecision,
        time: result.benchmarkResult.performance.timing.stimulusOnsetJitter,
        message: `Stimulus onset jitter: ${result.benchmarkResult.performance.timing.stimulusOnsetJitter.toFixed(2)}ms`
      },
      {
        name: 'FrameRate',
        passed: result.benchmarkResult.performance.fps.percentiles.p95 >= this.config.thresholds.fpsMinimum,
        time: 0,
        message: `95th percentile FPS: ${result.benchmarkResult.performance.fps.percentiles.p95.toFixed(1)}`
      },
      {
        name: 'FrameVariance',
        passed: result.benchmarkResult.performance.frameVariance.standardDeviation <= this.config.thresholds.frameVariance,
        time: result.benchmarkResult.performance.frameVariance.standardDeviation,
        message: `Frame variance: ${result.benchmarkResult.performance.frameVariance.standardDeviation.toFixed(2)}ms`
      },
      {
        name: 'MemoryUsage',
        passed: result.benchmarkResult.performance.memory.heapUsed <= this.config.thresholds.memoryLimit,
        time: 0,
        message: `Heap usage: ${result.benchmarkResult.performance.memory.heapUsed.toFixed(1)}MB`
      }
    ];

    const failures = testCases.filter(tc => !tc.passed).length;

    let xml = `<?xml version="1.0" encoding="UTF-8"?>
<testsuites name="PsyForge Timing Validation" tests="${testCases.length}" failures="${failures}" time="${Date.now() - result.timestamp}">
  <testsuite name="Hardware Timing" tests="${testCases.length}" failures="${failures}">
`;

    testCases.forEach(tc => {
      xml += `    <testcase name="${tc.name}" time="${tc.time}">
`;
      if (!tc.passed) {
        xml += `      <failure message="${tc.message}" />
`;
      }
      xml += `    </testcase>
`;
    });

    xml += `  </testsuite>
</testsuites>`;

    return xml;
  }

  /**
   * Save current results as new baseline
   */
  async saveBaseline(result: CIValidationResult, file: string): Promise<void> {
    const baseline: BaselineData = {
      version: '1.0.0',
      timestamp: result.timestamp,
      environment: `${result.environment.platform}-${result.environment.node}`,
      metrics: {
        timingPrecision: result.benchmarkResult.performance.timing.stimulusOnsetJitter,
        avgFPS: result.benchmarkResult.performance.fps.average,
        frameVariance: result.benchmarkResult.performance.frameVariance.standardDeviation,
        memoryUsage: result.benchmarkResult.performance.memory.heapUsed
      }
    };

    try {
      const fs = await import('fs/promises');
      await fs.writeFile(file, JSON.stringify(baseline, null, 2));
      console.log(`✅ Saved new baseline to ${file}`);
    } catch (error) {
      console.error(`❌ Failed to save baseline: ${error}`);
    }
  }
}

