/**
 * Tests for Hardware Timing Validation
 */

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { HardwareBenchmark, BenchmarkResult } from './hardware-benchmark';

// Mock browser APIs
const mockPerformanceNow = vi.fn();
const mockRequestAnimationFrame = vi.fn();

// @ts-ignore
global.performance = {
  now: mockPerformanceNow
};

// @ts-ignore
global.requestAnimationFrame = mockRequestAnimationFrame;

// @ts-ignore
global.navigator = {
  userAgent: 'Test Browser',
  platform: 'Test Platform',
  hardwareConcurrency: 8,
  deviceMemory: 16
};

// @ts-ignore
global.window = {
  screen: {
    width: 1920,
    height: 1080,
    colorDepth: 24
  },
  devicePixelRatio: 2,
  AudioContext: class MockAudioContext {}
};

// @ts-ignore
global.HTMLVideoElement = {
  prototype: {}
};

describe('HardwareBenchmark', () => {
  let benchmark: HardwareBenchmark;

  beforeEach(() => {
    vi.clearAllMocks();
    benchmark = new HardwareBenchmark({
      iterations: 10,
      warmupIterations: 2,
      measurementDuration: 100
    });

    // Mock performance.now to return incrementing values
    let time = 0;
    mockPerformanceNow.mockImplementation(() => {
      time += 16.67; // Simulate 60 FPS
      return time;
    });

    // Mock requestAnimationFrame to call immediately
    mockRequestAnimationFrame.mockImplementation((callback: Function) => {
      setTimeout(() => callback(mockPerformanceNow()), 0);
      return 1;
    });
  });

  describe('Device Detection', () => {
    it('should collect device information', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.device).toBeDefined();
      expect(result.device.userAgent).toBe('Test Browser');
      expect(result.device.platform).toBe('Test Platform');
      expect(result.device.cores).toBe(8);
      expect(result.device.memory).toBe(16);
    });

    it('should detect display information', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.display).toBeDefined();
      expect(result.display.resolution.width).toBe(1920);
      expect(result.display.resolution.height).toBe(1080);
      expect(result.display.colorDepth).toBe(24);
      expect(result.display.pixelRatio).toBe(2);
    });

    it('should detect browser features', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.browser).toBeDefined();
      expect(result.browser.features.performanceAPI).toBe(true);
      expect(result.browser.features.webAudioAPI).toBe(true);
      expect(result.browser.features.requestVideoFrameCallback).toBe(false);
    });
  });

  describe('Performance Metrics', () => {
    it('should measure FPS metrics', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.performance.fps).toBeDefined();
      expect(result.performance.fps.average).toBeGreaterThan(0);
      expect(result.performance.fps.min).toBeLessThanOrEqual(result.performance.fps.max);
      expect(result.performance.fps.percentiles.p50).toBeGreaterThan(0);
    });

    it('should measure timing precision', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.performance.timing).toBeDefined();
      expect(result.performance.timing.clockPrecision).toBeGreaterThan(0);
      expect(result.performance.timing.stimulusOnsetJitter).toBeGreaterThan(0);
      expect(result.performance.timing.frameTimingAccuracy).toBeLessThanOrEqual(100);
    });

    it('should measure memory usage', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.performance.memory).toBeDefined();
      expect(result.performance.memory.heapUsed).toBeGreaterThanOrEqual(0);
      expect(result.performance.memory.gcPauses).toBeInstanceOf(Array);
    });

    it('should measure frame variance', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.performance.frameVariance).toBeDefined();
      expect(result.performance.frameVariance.standardDeviation).toBeGreaterThanOrEqual(0);
      expect(result.performance.frameVariance.droppedFrames).toBeGreaterThanOrEqual(0);
    });
  });

  describe('Validation', () => {
    it('should validate results against thresholds', async () => {
      const result = await benchmark.runFullBenchmark();

      expect(result.validation).toBeDefined();
      expect(typeof result.validation.passed).toBe('boolean');
      expect(typeof result.validation.timingPrecisionMet).toBe('boolean');
      expect(result.validation.warnings).toBeInstanceOf(Array);
      expect(result.validation.recommendations).toBeInstanceOf(Array);
    });

    it('should fail validation with poor timing', async () => {
      // Mock poor timing performance
      let time = 0;
      mockPerformanceNow.mockImplementation(() => {
        time += 16.67 + Math.random() * 10; // Add jitter
        return time;
      });

      const result = await benchmark.runFullBenchmark();

      expect(result.validation.timingPrecisionMet).toBe(false);
      expect(result.validation.warnings.length).toBeGreaterThan(0);
    });
  });

  describe('Reporting', () => {
    it('should generate markdown report', async () => {
      await benchmark.runFullBenchmark();
      const report = benchmark.generateReport();

      expect(report).toContain('Hardware Timing Validation Report');
      expect(report).toContain('System Information');
      expect(report).toContain('Performance Results');
      expect(report).toContain('Validation Results');
    });

    it('should export results as JSON', async () => {
      await benchmark.runFullBenchmark();
      const json = benchmark.exportResults();

      const parsed = JSON.parse(json);
      expect(parsed).toBeInstanceOf(Array);
      expect(parsed.length).toBeGreaterThan(0);
      expect(parsed[0]).toHaveProperty('timestamp');
      expect(parsed[0]).toHaveProperty('performance');
    });
  });

  describe('Compatibility Matrix', () => {
    it('should generate compatibility matrix for different refresh rates', async () => {
      const matrix = await benchmark.generateCompatibilityMatrix();

      expect(matrix.size).toBe(4); // 60Hz, 120Hz, 144Hz, 240Hz
      expect(matrix.has('60Hz')).toBe(true);
      expect(matrix.has('120Hz')).toBe(true);
      expect(matrix.has('144Hz')).toBe(true);
      expect(matrix.has('240Hz')).toBe(true);
    });
  });
});

