import * as PIXI from 'pixi.js';
import type { TimelineContext } from '../core/Timeline.js';
import { BaseStimulus } from './BaseStimulus.js';
import { PerformanceMonitor } from '../validation/PerformanceMonitor.js';

export interface RendererOptions {
  width?: number;
  height?: number;
  backgroundColor?: number | string;
  antialias?: boolean;
  resolution?: number;
  powerPreference?: 'high-performance' | 'low-power' | 'default';
  preserveDrawingBuffer?: boolean;
  preferWebGL2?: boolean;
  enableFallback?: boolean;
}

export interface RendererCapabilities {
  webGL2: boolean;
  webGL1: boolean;
  canvas2D: boolean;
  maxTextureSize: number;
  maxRenderBufferSize: number;
  supportedExtensions: string[];
  renderer: 'webgl2' | 'webgl' | 'canvas' | 'unknown';
}

export class EnhancedStimulusRenderer {
  private static instance: EnhancedStimulusRenderer;
  private app?: PIXI.Application;
  private activeStimuli: Map<string, BaseStimulus> = new Map();
  private isInitialized = false;
  private capabilities: RendererCapabilities;
  private performanceMonitor?: PerformanceMonitor;
  private canvas2DFallback?: HTMLCanvasElement;
  private canvas2DContext?: CanvasRenderingContext2D;
  private useFallback = false;

  private constructor() {
    this.capabilities = this.detectCapabilities();
  }

  static getInstance(): EnhancedStimulusRenderer {
    if (!EnhancedStimulusRenderer.instance) {
      EnhancedStimulusRenderer.instance = new EnhancedStimulusRenderer();
    }
    return EnhancedStimulusRenderer.instance;
  }

  private detectCapabilities(): RendererCapabilities {
    const canvas = document.createElement('canvas');

    // Check WebGL2
    const gl2 = canvas.getContext('webgl2');
    const hasWebGL2 = gl2 !== null;

    // Check WebGL1
    const gl1 = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
    const hasWebGL1 = gl1 !== null;

    // Check Canvas2D
    const ctx2d = canvas.getContext('2d');
    const hasCanvas2D = ctx2d !== null;

    // Get capabilities from available context
    let maxTextureSize = 4096;
    let maxRenderBufferSize = 4096;
    let supportedExtensions: string[] = [];
    let renderer: RendererCapabilities['renderer'] = 'unknown';

    if (gl2) {
      maxTextureSize = gl2.getParameter(gl2.MAX_TEXTURE_SIZE);
      maxRenderBufferSize = gl2.getParameter(gl2.MAX_RENDERBUFFER_SIZE);
      supportedExtensions = gl2.getSupportedExtensions() || [];
      renderer = 'webgl2';
    } else if (gl1) {
      maxTextureSize = (gl1 as WebGLRenderingContext).getParameter((gl1 as WebGLRenderingContext).MAX_TEXTURE_SIZE);
      maxRenderBufferSize = (gl1 as WebGLRenderingContext).getParameter((gl1 as WebGLRenderingContext).MAX_RENDERBUFFER_SIZE);
      supportedExtensions = (gl1 as WebGLRenderingContext).getSupportedExtensions() || [];
      renderer = 'webgl';
    } else if (hasCanvas2D) {
      renderer = 'canvas';
    }

    return {
      webGL2: hasWebGL2,
      webGL1: hasWebGL1,
      canvas2D: hasCanvas2D,
      maxTextureSize,
      maxRenderBufferSize,
      supportedExtensions,
      renderer
    };
  }

  getCapabilities(): RendererCapabilities {
    return { ...this.capabilities };
  }

  async initialize(options: RendererOptions = {}): Promise<void> {

