/**
 * JSON Declarative Experiment Schema
 * 
 * Provides a simpler alternative to the fluent API for basic experiments.
 * Addresses the API complexity concern by offering a data-driven approach.
 */

import { z } from 'zod';

// Stimulus Types
export const TextStimulusSchema = z.object({
  type: z.literal('text'),
  content: z.string(),
  duration: z.number().optional(),
  position: z.object({
    x: z.number().default(0),
    y: z.number().default(0)
  }).optional(),
  style: z.object({
    fontSize: z.number().optional(),
    color: z.string().optional(),
    fontFamily: z.string().optional()
  }).optional()
});

export const ImageStimulusSchema = z.object({
  type: z.literal('image'),
  src: z.string(),
  duration: z.number().optional(),
  position: z.object({
    x: z.number().default(0),
    y: z.number().default(0)
  }).optional(),
  size: z.object({
    width: z.number().optional(),
    height: z.number().optional()
  }).optional()
});

export const AudioStimulusSchema = z.object({
  type: z.literal('audio'),
  src: z.string(),
  duration: z.number().optional(),
  volume: z.number().min(0).max(1).default(1)
});

export const StimulusSchema = z.discriminatedUnion('type', [
  TextStimulusSchema,
  ImageStimulusSchema,
  AudioStimulusSchema
]);

// Response Types
export const KeyboardResponseSchema = z.object({
  type: z.literal('keyboard'),
  validKeys: z.array(z.string()).optional(),
  timeout: z.number().optional(),
  correctResponse: z.string().optional()
});

export const MouseResponseSchema = z.object({
  type: z.literal('mouse'),
  validButtons: z.array(z.enum(['left', 'right', 'middle'])).optional(),
  timeout: z.number().optional(),
  targetArea: z.object({
    x: z.number(),
    y: z.number(),
    width: z.number(),
    height: z.number()
  }).optional()
});

export const ResponseSchema = z.discriminatedUnion('type', [
  KeyboardResponseSchema,
  MouseResponseSchema
]);

// Trial Schema
export const TrialSchema = z.object({
  id: z.string().optional(),
  stimulus: z.union([StimulusSchema, z.array(StimulusSchema)]),
  response: ResponseSchema.optional(),
  fixation: z.object({
    duration: z.number(),
    symbol: z.string().default('+')
  }).optional(),
  feedback: z.object({
    enabled: z.boolean().default(false),
    duration: z.number().default(500),
    correct: z.string().default('Correct!'),
    incorrect: z.string().default('Incorrect')
  }).optional(),
  iti: z.number().optional() // Inter-trial interval
});

// Block Schema
export const BlockSchema = z.object({
  id: z.string().optional(),
  name: z.string().optional(),
  trials: z.array(TrialSchema),
  randomize: z.boolean().default(false),
  repetitions: z.number().default(1),
  instructions: z.string().optional()
});

// Experiment Schema
export const ExperimentSchema = z.object({
  version: z.string().regex(/^\d+\.\d+$/),
  metadata: z.object({
    name: z.string(),
    description: z.string().optional(),
    author: z.string().optional(),
    date: z.string().optional(),
    tags: z.array(z.string()).optional()
  }),
  settings: z.object({
    backgroundColor: z.string().default('#000000'),
    fontFamily: z.string().default('Arial'),
    fontSize: z.number().default(32),
    requireFullscreen: z.boolean().default(true),
    showProgressBar: z.boolean().default(false)
  }).optional(),
  blocks: z.array(BlockSchema),
  dataCollection: z.object({
    saveTrialData: z.boolean().default(true),
    saveTimingData: z.boolean().default(true),
    customVariables: z.record(z.any()).optional()
  }).optional()
});

// Type exports
export type TextStimulus = z.infer<typeof TextStimulusSchema>;
export type ImageStimulus = z.infer<typeof ImageStimulusSchema>;
export type AudioStimulus = z.infer<typeof AudioStimulusSchema>;
export type Stimulus = z.infer<typeof StimulusSchema>;

export type KeyboardResponse = z.infer<typeof KeyboardResponseSchema>;
export type MouseResponse = z.infer<typeof MouseResponseSchema>;
export type Response = z.infer<typeof ResponseSchema>;

export type Trial = z.infer<typeof TrialSchema>;
export type Block = z.infer<typeof BlockSchema>;
export type ExperimentDefinition = z.infer<typeof ExperimentSchema>;

/**
 * Validate and parse JSON experiment definition
 */
export function parseExperimentJSON(json: unknown): ExperimentDefinition {
  return ExperimentSchema.parse(json);
}

/**
 * Example of a simple reaction time experiment in JSON
 */
export const EXAMPLE_SIMPLE_RT: ExperimentDefinition = {
  version: "1.0",
  metadata: {
    name: "Simple Reaction Time",
