/**
 * JSON to ForgeScript Compiler
 * 
 * Compiles declarative JSON experiments to ForgeScript fluent API code.
 * Provides an easier entry point for simple experiments.
 */

import { 
  ExperimentDefinition, 
  Trial, 
  Block, 
  Stimulus,
  Response,
  parseExperimentJSON 
} from './experiment-schema.js';
import { experiment } from '../builders/ExperimentBuilder.js';
import { Experiment } from '../core/Experiment.js';
import { Timeline } from '../core/Timeline.js';
import { 
  TextStimulusPixi, 
  ImageStimulusPixi, 
  AudioStimulus 
} from '../stimuli/index.js';
import { 
  KeyboardResponse, 
  MouseResponse 
} from '../responses/index.js';

export class JSONExperimentCompiler {
  /**
   * Compile JSON experiment definition to executable experiment
   */
  static compile(jsonDef: ExperimentDefinition | string): Experiment {
    // Parse if string
    const def = typeof jsonDef === 'string' 
      ? parseExperimentJSON(JSON.parse(jsonDef))
      : jsonDef;

    // Create experiment builder
    const builder = experiment()
      .name(def.metadata.name)
      .description(def.metadata.description || '');

    // Apply settings
    if (def.settings) {
      builder.configure({
        display: {
          backgroundColor: def.settings.backgroundColor,
          fullscreen: def.settings.requireFullscreen
        }
      });
    }

    // Add metadata
    if (def.metadata.author) {
      builder.author(def.metadata.author);
    }
    if (def.metadata.tags) {
      def.metadata.tags.forEach(tag => builder.tag(tag));
    }

    // Compile blocks
    def.blocks.forEach(blockDef => {
      const timeline = this.compileBlock(blockDef);
      builder.addTimeline(timeline);
    });

    return builder.build();
  }

  /**
   * Compile block definition to timeline
   */
  private static compileBlock(blockDef: Block): Timeline {
    const timeline = new Timeline({
      name: blockDef.name || `block_${Date.now()}`
    });

    // Add instructions if present
    if (blockDef.instructions) {
      const instructionStim = new TextStimulusPixi({
        content: blockDef.instructions,
        duration: 0 // Wait for response
      });

      timeline.add({
        stimuli: [instructionStim],
        response: new KeyboardResponse({
          validKeys: ['space'],
          name: 'continue'
        })
      });
    }

    // Process trials
    let trials = blockDef.trials;

    // Handle repetitions
    if (blockDef.repetitions > 1) {
      trials = Array(blockDef.repetitions).fill(null)
        .flatMap(() => blockDef.trials);
    }

    // Handle randomization
    if (blockDef.randomize) {
      trials = this.shuffleArray([...trials]);
    }

    // Compile each trial
    trials.forEach((trialDef, index) => {
      this.compileTrial(timeline, trialDef, `${blockDef.id || 'block'}_trial_${index}`);
    });

    return timeline;
  }

  /**
   * Compile trial definition to timeline events
   */
  private static compileTrial(
    timeline: Timeline, 
    trialDef: Trial, 
    trialId: string
  ): void {
    // Add fixation if present
    if (trialDef.fixation) {
      const fixationStim = new TextStimulusPixi({
        content: trialDef.fixation.symbol,
        duration: trialDef.fixation.duration
      });

      timeline.add({
        stimuli: [fixationStim],
        duration: trialDef.fixation.duration
      });
    }

    // Compile stimuli
    const stimuli = Array.isArray(trialDef.stimulus) 
      ? trialDef.stimulus.map(s => this.compileStimulus(s))
      : [this.compileStimulus(trialDef.stimulus)];

    // Compile response
    const response = trialDef.response 
      ? this.compileResponse(trialDef.response)
      : undefined;

    // Add main trial
    const trialData: any = {
      stimuli,
      metadata: { trialId }
    };

    if (response) {
      trialData.response = response;
    }

    // Set duration from stimulus if no response
    if (!response && stimuli.length > 0 && stimuli[0].duration) {
      trialData.duration = stimuli[0].duration;
    }

    timeline.add(trialData);

    // Add feedback if enabled
    if (trialDef.feedback?.enabled && response) {
      timeline.add({
        stimuli: [],
        onStart: (context) => {
          const lastResponse = context.data.getLastTrial();
          const correct = lastResponse?.correct || false;

          const feedbackText = correct 
            ? trialDef.feedback!.correct 
            : trialDef.feedback!.incorrect;

          const feedbackStim = new TextStimulusPixi({
            content: feedbackText,
            duration: trialDef.feedback!.duration,
            style: {
              fill: correct ? 0x00FF00 : 0xFF0000
            }
          });

          context.addStimulus(feedbackStim);
        },
        duration: trialDef.feedback.duration
      });
    }

    // Add inter-trial interval
    if (trialDef.iti) {
      timeline.add({
        stimuli: [],
        duration: trialDef.iti
      });
    }
  }

  /**
   * Compile stimulus definition
   */
  private static compileStimulus(stimDef: Stimulus): any {
    switch (stimDef.type) {
      case 'text':
        return new TextStimulusPixi({
          content: stimDef.content,
          duration: stimDef.duration,
          x: stimDef.position?.x || 0,
          y: stimDef.position?.y || 0,
          style: {
            fontSize: stimDef.style?.fontSize,
            fill: stimDef.style?.color,
            fontFamily: stimDef.style?.fontFamily
          }
        });

      case 'image':
        return new ImageStimulusPixi({
          src: stimDef.src,
          duration: stimDef.duration,
          x: stimDef.position?.x || 0,
          y: stimDef.position?.y || 0,
          width: stimDef.size?.width,
          height: stimDef.size?.height
        });

      case 'audio':
        return new AudioStimulus({
          src: stimDef.src,
          duration: stimDef.duration,
          volume: stimDef.volume
        });

      default:
        throw new Error(`Unknown stimulus type: ${(stimDef as any).type}`);
    }
  }

  /**
   * Compile response definition
   */
  private static compileResponse(respDef: Response): any {
    switch (respDef.type) {
      case 'keyboard':
        return new KeyboardResponse({
          validKeys: respDef.validKeys,
          timeout: respDef.timeout,
          correctResponse: respDef.correctResponse,
          name: 'response'
        });

      case 'mouse':
        return new MouseResponse({
          validButtons: respDef.validButtons,
          timeout: respDef.timeout,
          name: 'response'
        });

      default:
        throw new Error(`Unknown response type: ${(respDef as any).type}`);
    }
  }

  /**
   * Shuffle array using Fisher-Yates algorithm
   */
  private static shuffleArray<T>(array: T[]): T[] {
    const shuffled = [...array];
    for (let i = shuffled.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    return shuffled;
  }

  /**
   * Convert ForgeScript experiment back to JSON (for round-trip)
   */
  static decompile(exp: Experiment): ExperimentDefinition {
    // This would be implemented to support round-trip conversion
    // For now, throw not implemented
    throw new Error('Decompilation not yet implemented');
  }
}

/**
 * Convenience function to run JSON experiments
 */
export async function runJSONExperiment(
  jsonDef: ExperimentDefinition | string,
  participantId?: string
): Promise<void> {
  const exp = JSONExperimentCompiler.compile(jsonDef);

  if (participantId) {
    exp.dataCollector.setParticipantId(participantId);
  }

  await exp.run();
}

/**
 * Load and run JSON experiment from URL
 */
export async function runJSONExperimentFromURL(
  url: string,
  participantId?: string
): Promise<void> {
  const response = await fetch(url);
  const jsonDef = await response.json();

  return runJSONExperiment(jsonDef, participantId);
}

// Export for convenience
export { parseExperimentJSON, ExperimentSchema } from './experiment-schema.js';

