#!/usr/bin/env node

/**
 * API Surface Linter
 * 
 * Monitors ForgeScript API growth and complexity to prevent "builder hell".
 * Enforces rules defined in .forgescript-api-lint.json
 */

import * as ts from 'typescript';
import * as fs from 'fs/promises';
import * as path from 'path';
import { glob } from 'glob';

interface LintConfig {
  version: string;
  rules: {
    maxPublicMethods: number;
    maxMethodParameters: number;
    maxChainDepth: number;
    requireDocumentation: boolean;
    requireExamples: boolean;
  };
  complexity: {
    maxFileSize: number;
    maxClassSize: number;
    maxFunctionSize: number;
    maxCyclomaticComplexity: number;
  };
  apiCategories: {
    [key: string]: {
      path: string;
      maxGrowthPerVersion: number;
    };
  };
  exclude: string[];
}

interface LintResult {
  passed: boolean;
  violations: Violation[];
  metrics: ApiMetrics;
  suggestions: string[];
}

interface Violation {
  file: string;
  line: number;
  column: number;
  rule: string;
  message: string;
  severity: 'error' | 'warning';
}

interface ApiMetrics {
  totalPublicMethods: number;
  totalClasses: number;
  averageMethodParams: number;
  maxChainDepth: number;
  documentationCoverage: number;
  categoryCounts: { [key: string]: number };
}

export class ApiLinter {
  private config: LintConfig;
  private violations: Violation[] = [];
  private metrics: ApiMetrics = {
    totalPublicMethods: 0,
    totalClasses: 0,
    averageMethodParams: 0,
    maxChainDepth: 0,
    documentationCoverage: 0,
    categoryCounts: {}
  };

  constructor(configPath: string = '.forgescript-api-lint.json') {
    const configContent = require(path.resolve(configPath));
    this.config = configContent;
  }

  async lint(targetPath: string = 'src'): Promise<LintResult> {
    console.log('🔍 Linting ForgeScript API surface...\n');

    // Find all TypeScript files
    const files = await this.findFiles(targetPath);

    // Analyze each file
    for (const file of files) {
      await this.analyzeFile(file);
    }

    // Calculate final metrics
    this.calculateMetrics();

    // Generate suggestions
    const suggestions = this.generateSuggestions();

    // Determine pass/fail
    const passed = this.violations.filter(v => v.severity === 'error').length === 0;

    return {
      passed,
      violations: this.violations,
      metrics: this.metrics,
      suggestions
    };
  }

  private async findFiles(targetPath: string): Promise<string[]> {
    const pattern = path.join(targetPath, '**/*.ts');
    const files = await glob(pattern, {
      ignore: this.config.exclude
    });
    return files;
  }

  private async analyzeFile(filePath: string): Promise<void> {
    const content = await fs.readFile(filePath, 'utf-8');
    const sourceFile = ts.createSourceFile(
      filePath,
      content,
      ts.ScriptTarget.Latest,
      true
    );

    // Check file size
    const lines = content.split('\n').length;
    if (lines > this.config.complexity.maxFileSize) {
      this.addViolation(filePath, 1, 1, 'file-size', 
        `File exceeds maximum size (${lines} > ${this.config.complexity.maxFileSize} lines)`,
        'warning'
      );
    }

    // Traverse AST
    this.visit(sourceFile, sourceFile);
  }

  private visit(node: ts.Node, sourceFile: ts.SourceFile): void {
    // Check classes
    if (ts.isClassDeclaration(node) && node.name) {
      this.analyzeClass(node, sourceFile);
    }

    // Check methods
    if (ts.isMethodDeclaration(node)) {
      this.analyzeMethod(node, sourceFile);
    }

    // Check functions
    if (ts.isFunctionDeclaration(node)) {
      this.analyzeFunction(node, sourceFile);
    }

    // Recurse
    ts.forEachChild(node, child => this.visit(child, sourceFile));
  }

  private analyzeClass(node: ts.ClassDeclaration, sourceFile: ts.SourceFile): void {
    this.metrics.totalClasses++;

    const className = node.name!.text;
    const publicMethods = node.members.filter(member => 
      ts.isMethodDeclaration(member) && 
      !this.hasModifier(member, ts.SyntaxKind.PrivateKeyword) &&
      !this.hasModifier(member, ts.SyntaxKind.ProtectedKeyword)
    );

    // Count public methods
    this.metrics.totalPublicMethods += publicMethods.length;

    // Check class size
    const classLines = this.getNodeLines(node, sourceFile);
    if (classLines > this.config.complexity.maxClassSize) {
      const { line } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
      this.addViolation(
        sourceFile.fileName, 
        line + 1, 
        1, 
        'class-size',
        `Class ${className} exceeds maximum size (${classLines} > ${this.config.complexity.maxClassSize} lines)`,
        'warning'
      );
    }

    // Check documentation
    if (this.config.rules.requireDocumentation && !this.hasJSDoc(node)) {
      const { line } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
      this.addViolation(
        sourceFile.fileName,
        line + 1,
        1,
        'missing-docs',
        `Class ${className} is missing JSDoc documentation`,
        'error'
      );
    }

    // Detect builder pattern chains
    this.detectBuilderChains(node, sourceFile);
  }

  private analyzeMethod(node: ts.MethodDeclaration, sourceFile: ts.SourceFile): void {
    const methodName = node.name?.getText() || 'anonymous';

    // Check parameter count
    const paramCount = node.parameters.length;
    if (paramCount > this.config.rules.maxMethodParameters) {
      const { line } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
      this.addViolation(
        sourceFile.fileName,
        line + 1,
        1,
        'too-many-params',
        `Method ${methodName} has too many parameters (${paramCount} > ${this.config.rules.maxMethodParameters})`,
        'error'
      );
    }

    // Check method size
    const methodLines = this.getNodeLines(node, sourceFile);
    if (methodLines > this.config.complexity.maxFunctionSize) {
      const { line } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
      this.addViolation(
        sourceFile.fileName,
        line + 1,
        1,
        'method-size',
        `Method ${methodName} exceeds maximum size (${methodLines} > ${this.config.complexity.maxFunctionSize} lines)`,
        'warning'
      );
    }

    // Check cyclomatic complexity
    const complexity = this.calculateCyclomaticComplexity(node);
    if (complexity > this.config.complexity.maxCyclomaticComplexity) {
      const { line } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
      this.addViolation(
        sourceFile.fileName,
        line + 1,
        1,
        'cyclomatic-complexity',
        `Method ${methodName} has high cyclomatic complexity (${complexity} > ${this.config.complexity.maxCyclomaticComplexity})`,
        'warning'
      );
    }
  }

  private analyzeFunction(node: ts.FunctionDeclaration, sourceFile: ts.SourceFile): void {
    // Similar to analyzeMethod
    const functionName = node.name?.text || 'anonymous';

    // Check documentation
    if (this.config.rules.requireDocumentation && !this.hasJSDoc(node)) {
      const { line } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
      this.addViolation(
        sourceFile.fileName,
        line + 1,
        1,
        'missing-docs',
        `Function ${functionName} is missing JSDoc documentation`,
        'error'
      );
    }
  }

  private detectBuilderChains(node: ts.ClassDeclaration, sourceFile: ts.SourceFile): void {
    // Look for methods that return 'this' (builder pattern)
    let maxChain = 0;

    node.members.forEach(member => {
      if (ts.isMethodDeclaration(member)) {
        const returnType = member.type;
        if (returnType && returnType.kind === ts.SyntaxKind.ThisType) {
          maxChain++;
        }
      }
    });

    if (maxChain > this.metrics.maxChainDepth) {
      this.metrics.maxChainDepth = maxChain;
    }

    if (maxChain > this.config.rules.maxChainDepth) {
      const { line } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
      this.addViolation(
        sourceFile.fileName,
        line + 1,
        1,
        'chain-depth',
        `Class ${node.name!.text} allows chains up to ${maxChain} deep (max: ${this.config.rules.maxChainDepth})`,
        'warning'
      );
    }
  }

  private calculateCyclomaticComplexity(node: ts.Node): number {
    let complexity = 1;

    const visit = (n: ts.Node) => {
      switch (n.kind) {
        case ts.SyntaxKind.IfStatement:
        case ts.SyntaxKind.ConditionalExpression:
        case ts.SyntaxKind.CatchClause:
        case ts.SyntaxKind.CaseClause:
        case ts.SyntaxKind.DefaultClause:
          complexity++;
          break;
        case ts.SyntaxKind.WhileStatement:
        case ts.SyntaxKind.ForStatement:
        case ts.SyntaxKind.ForInStatement:
        case ts.SyntaxKind.ForOfStatement:
        case ts.SyntaxKind.DoStatement:
          complexity++;
          break;
        case ts.SyntaxKind.BinaryExpression:
          const binary = n as ts.BinaryExpression;
          if (binary.operatorToken.kind === ts.SyntaxKind.AmpersandAmpersandToken ||
              binary.operatorToken.kind === ts.SyntaxKind.BarBarToken) {
            complexity++;
          }
          break;
      }
      ts.forEachChild(n, visit);
    };

    visit(node);
    return complexity;
  }

  private hasModifier(node: ts.Node, kind: ts.SyntaxKind): boolean {
    return node.modifiers?.some(m => m.kind === kind) || false;
  }

  private hasJSDoc(node: ts.Node): boolean {
    const jsDocTags = ts.getJSDocTags(node);
    return jsDocTags.length > 0;
  }

  private getNodeLines(node: ts.Node, sourceFile: ts.SourceFile): number {
    const start = sourceFile.getLineAndCharacterOfPosition(node.getStart());
    const end = sourceFile.getLineAndCharacterOfPosition(node.getEnd());
    return end.line - start.line + 1;
  }

  private addViolation(
    file: string, 
    line: number, 
    column: number,
    rule: string,
    message: string,
    severity: 'error' | 'warning'
  ): void {
    this.violations.push({
      file: path.relative(process.cwd(), file),
      line,
      column,
      rule,
      message,
      severity
    });
  }

  private calculateMetrics(): void {
    // Documentation coverage
    const totalItems = this.metrics.totalClasses + this.metrics.totalPublicMethods;
    const documented = this.violations.filter(v => v.rule === 'missing-docs').length;
    this.metrics.documentationCoverage = totalItems > 0 
      ? ((totalItems - documented) / totalItems) * 100 
      : 100;
  }

  private generateSuggestions(): string[] {
    const suggestions: string[] = [];

    // API surface size
    if (this.metrics.totalPublicMethods > this.config.rules.maxPublicMethods) {
      suggestions.push(
        `Consider moving some methods to extended API modules. ` +
        `Current: ${this.metrics.totalPublicMethods}, Max: ${this.config.rules.maxPublicMethods}`
      );
    }

    // Chain depth
    if (this.metrics.maxChainDepth > this.config.rules.maxChainDepth - 2) {
      suggestions.push(
        `Builder chain depth approaching limit. Consider adding shortcuts for common patterns.`
      );
    }

    // Documentation
    if (this.metrics.documentationCoverage < 90) {
      suggestions.push(
        `Documentation coverage is ${this.metrics.documentationCoverage.toFixed(1)}%. ` +
        `Aim for >90% coverage.`
      );
    }

    // Complexity
    const complexViolations = this.violations.filter(v => v.rule === 'cyclomatic-complexity');
    if (complexViolations.length > 0) {
      suggestions.push(
        `${complexViolations.length} methods have high complexity. ` +
        `Consider breaking them into smaller functions.`
      );
    }

    return suggestions;
  }

  async generateReport(result: LintResult): Promise<string> {
    let report = `# ForgeScript API Lint Report

**Date**: ${new Date().toISOString()}
**Status**: ${result.passed ? '✅ PASSED' : '❌ FAILED'}

## Metrics

- **Total Public Methods**: ${result.metrics.totalPublicMethods}
- **Total Classes**: ${result.metrics.totalClasses}
- **Max Chain Depth**: ${result.metrics.maxChainDepth}
- **Documentation Coverage**: ${result.metrics.documentationCoverage.toFixed(1)}%

## Violations

`;

    if (result.violations.length === 0) {
      report += 'No violations found! 🎉\n';
    } else {
      const errors = result.violations.filter(v => v.severity === 'error');
      const warnings = result.violations.filter(v => v.severity === 'warning');

      if (errors.length > 0) {
        report += `### Errors (${errors.length})\n\n`;
        errors.forEach(v => {
          report += `- **${v.file}:${v.line}** - ${v.message}\n`;
        });
        report += '\n';
      }

      if (warnings.length > 0) {
        report += `### Warnings (${warnings.length})\n\n`;
        warnings.forEach(v => {
          report += `- **${v.file}:${v.line}** - ${v.message}\n`;
        });
        report += '\n';
      }
    }

    if (result.suggestions.length > 0) {
      report += `## Suggestions\n\n`;
      result.suggestions.forEach(s => {
        report += `- ${s}\n`;
      });
    }

    return report;
  }
}

// CLI execution
if (require.main === module) {
  (async () => {
    const linter = new ApiLinter();
    const result = await linter.lint();
    const report = await linter.generateReport(result);

    console.log(report);

    if (!result.passed) {
      process.exit(1);
    }
  })();
}

