/**
 * Example: Using JSON format for simple experiments
 * 
 * Demonstrates how the declarative JSON format provides an easier
 * alternative to the fluent API for basic experiments.
 */

import { 
  runJSONExperiment, 
  ExperimentDefinition,
  JSONExperimentCompiler 
} from '../src/declarative/json-compiler';

// Example 1: Simple Reaction Time Task in JSON
const simpleRT: ExperimentDefinition = {
  version: "1.0",
  metadata: {
    name: "Simple Reaction Time Task",
    author: "Dr. Jane Smith",
    description: "Measure reaction time to visual stimuli",
    tags: ["reaction-time", "visual", "attention"]
  },
  settings: {
    backgroundColor: "#1a1a1a",
    fontSize: 48,
    requireFullscreen: true,
    showProgressBar: true
  },
  blocks: [
    {
      name: "Instructions",
      trials: [{
        stimulus: {
          type: "text",
          content: "Press SPACE as quickly as possible when you see a circle.\n\nPress SPACE to begin."
        },
        response: {
          type: "keyboard",
          validKeys: ["space"]
        }
      }]
    },
    {
      name: "Practice",
      instructions: "Let's practice! Remember: press SPACE when you see the circle.",
      trials: Array(5).fill(null).map(() => ({
        fixation: {
          duration: 1000 + Math.random() * 2000, // 1-3s random
          symbol: "+"
        },
        stimulus: {
          type: "text",
          content: "●",
          duration: 1000,
          style: {
            fontSize: 100,
            color: "#FFFFFF"
          }
        },
        response: {
          type: "keyboard",
          validKeys: ["space"],
          timeout: 1000
        },
        feedback: {
          enabled: true,
          duration: 500
        },
        iti: 500
      }))
    },
    {
      name: "Main Task",
      randomize: true,
      trials: Array(30).fill(null).map(() => ({
        fixation: {
          duration: 1500 + Math.random() * 2500, // 1.5-4s random
          symbol: "+"
        },
        stimulus: {
          type: "text",
          content: "●",
          duration: 1500,
          style: {
            fontSize: 100,
            color: "#FFFFFF"
          }
        },
        response: {
          type: "keyboard",
          validKeys: ["space"],
          timeout: 1500
        },
        iti: 1000
      }))
    },
    {
      name: "Complete",
      trials: [{
        stimulus: {
          type: "text",
          content: "Task complete!\n\nThank you for participating."
        },
        response: {
          type: "keyboard",
          validKeys: ["space"]
        }
      }]
    }
  ]
};

// Example 2: N-Back Task (more complex)
const nBackTask: ExperimentDefinition = {
  version: "1.0",
  metadata: {
    name: "2-Back Working Memory Task",
    description: "Test working memory with letter sequence"
  },
  blocks: [
    {
      name: "2-Back Task",
      trials: [
        // In a real implementation, you'd generate these programmatically
        { 
          stimulus: { type: "text", content: "A", duration: 500 },
          response: { type: "keyboard", validKeys: ["m", "n"], timeout: 2500 }
        },
        { 
          stimulus: { type: "text", content: "B", duration: 500 },
          response: { type: "keyboard", validKeys: ["m", "n"], timeout: 2500 }
        },
        { 
          stimulus: { type: "text", content: "A", duration: 500 },
          response: { 
            type: "keyboard", 
            validKeys: ["m", "n"], 
            correctResponse: "m", // Match!
            timeout: 2500 
          }
        },
        { 
          stimulus: { type: "text", content: "C", duration: 500 },
          response: { 
            type: "keyboard", 
            validKeys: ["m", "n"], 
            correctResponse: "n", // No match
            timeout: 2500 
          }
        }
      ]
    }
  ]
};

// Example 3: Mixed media experiment
const mixedMediaExp: ExperimentDefinition = {
  version: "1.0",
  metadata: {
    name: "Audiovisual Integration Task"
  },
  blocks: [
    {
      name: "AV Congruence",
      randomize: true,
      trials: [
        {
          // Congruent: dog image + dog sound
          stimulus: [
            { type: "image", src: "/stimuli/dog.jpg" },
            { type: "audio", src: "/stimuli/dog-bark.mp3" }
          ],
          response: {
            type: "keyboard",
            validKeys: ["c", "i"], // c=congruent, i=incongruent
            correctResponse: "c",
            timeout: 3000
          }
        },
        {
          // Incongruent: cat image + dog sound
          stimulus: [
            { type: "image", src: "/stimuli/cat.jpg" },
            { type: "audio", src: "/stimuli/dog-bark.mp3" }
          ],
          response: {
            type: "keyboard",
            validKeys: ["c", "i"],
            correctResponse: "i",
            timeout: 3000
          }
        }
      ]
    }
  ]
};

// Running JSON experiments
async function runExamples() {
  // Method 1: Direct JSON object
  await runJSONExperiment(simpleRT, "participant_001");

  // Method 2: From JSON string
  const jsonString = JSON.stringify(simpleRT);
  await runJSONExperiment(jsonString, "participant_002");

  // Method 3: From URL
  await runJSONExperimentFromURL(
    "https://example.com/experiments/simple-rt.json",
    "participant_003"
  );

  // Method 4: Compile to ForgeScript for customization
  const compiledExp = JSONExperimentCompiler.compile(simpleRT);

  // Can still customize after compilation
  compiledExp.configure({
    display: { 
      width: 1920, 
      height: 1080 
    }
  });

  await compiledExp.run();
}

// Validation example
function validateJSONExperiment() {
  try {
    // This will throw if JSON doesn't match schema
    const validated = JSONExperimentCompiler.compile({
      version: "1.0",
      metadata: { name: "Test" },
      blocks: [{
        trials: [{
          stimulus: { 
            type: "invalid", // Will fail validation
            content: "test" 
          }
        }]
      }]
    });
  } catch (error) {
    console.error("Validation failed:", error);
  }
}

// Comparison: JSON vs Fluent API
function compareApproaches() {
  // JSON Approach (simple, declarative)
  const jsonExp: ExperimentDefinition = {
    version: "1.0",
    metadata: { name: "Stroop Task" },
    blocks: [{
      trials: [{
        stimulus: { 
          type: "text", 
          content: "RED", 
          style: { color: "#00FF00" } 
        },
        response: { 
          type: "keyboard", 
          validKeys: ["r", "g", "b"] 
        }
      }]
    }]
  };

  // Fluent API Approach (powerful, flexible)
  import { experiment } from '../src/builders/ExperimentBuilder';

  const fluentExp = experiment()
    .name("Stroop Task")
    .trial()
      .stimulus({
        type: 'text',
        content: 'RED',
        style: { fill: 0x00FF00 }
      })
      .response({
        device: 'keyboard',
        validKeys: ['r', 'g', 'b']
      })
    .build();

  // Both create equivalent experiments!
}

// Export for testing
export { simpleRT, nBackTask, mixedMediaExp };

